                NDS_VEC_VSRA_VX(NDS_VEC_V6, NDS_VEC_V6, pre_rshift);

                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
                NDS_VEC_VMUL_VX(NDS_VEC_V2, NDS_VEC_V2, out_scale);
                NDS_VEC_VMUL_VX(NDS_VEC_V4, NDS_VEC_V4, out_scale);
                NDS_VEC_VMUL_VX(NDS_VEC_V6, NDS_VEC_V6, out_scale);

                NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VMAX_VX(NDS_VEC_V2, NDS_VEC_V2, 0);
                NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, 0);
                NDS_VEC_VMAX_VX(NDS_VEC_V6, NDS_VEC_V6, 0);

                // Narrow e32->e16 with post_rshift (unsigned clip)
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIPU_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
                NDS_VEC_VNCLIPU_WX(NDS_VEC_V2, NDS_VEC_V2, post_rshift);
                NDS_VEC_VNCLIPU_WX(NDS_VEC_V4, NDS_VEC_V4, post_rshift);
                NDS_VEC_VNCLIPU_WX(NDS_VEC_V6, NDS_VEC_V6, post_rshift);

                // Narrow e16->e8 (unsigned clip)
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIPU_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VNCLIPU_WI(NDS_VEC_V2, NDS_VEC_V2, 0);
                NDS_VEC_VNCLIPU_WI(NDS_VEC_V4, NDS_VEC_V4, 0);
                NDS_VEC_VNCLIPU_WI(NDS_VEC_V6, NDS_VEC_V6, 0);

                // Store 4 output pixels, each with rhs_rows stride
                NDS_VEC_VSE8_V(NDS_VEC_V0, dst_ptr);
                dst_ptr += rhs_rows;
                NDS_VEC_VSE8_V(NDS_VEC_V2, dst_ptr);
                dst_ptr += rhs_rows;
                NDS_VEC_VSE8_V(NDS_VEC_V4, dst_ptr);
                dst_ptr += rhs_rows;
                NDS_VEC_VSE8_V(NDS_VEC_V6, dst_ptr);
                dst_ptr += rhs_rows;
                lhs_ptr -= rhs_cols;
                lhs_ptr += 4 * lhs_cols_offset;
                lhs_rows_idx--;
            }

            // Left-over lhs rows (1-3 pixels)
            long rest_lhs_row = lhs_rows & 3;
            while(rest_lhs_row-- > 0)
            {
                const q7_t *rhs_ptr  = &rhs[0];
                q7_t *rhs_ptr2 = (q7_t *)&rhs_ptr[rhs_cols];
                q7_t *rhs_ptr3 = (q7_t *)&rhs_ptr[rhs_cols * 2];
                q7_t *rhs_ptr4 = (q7_t *)&rhs_ptr[rhs_cols * 3];
                long rhs_cols2 = rhs_cols;

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
                NDS_VEC_VAND_VI(NDS_VEC_V14, NDS_VEC_V14, 0x0);
                NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0x0);
                NDS_VEC_VAND_VI(NDS_VEC_V18, NDS_VEC_V18, 0x0);

                while(rhs_cols2 >= max_vl_per_vg_e8m1)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VLE8_V(NDS_VEC_V4, rhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V6, rhs_ptr2);
                    NDS_VEC_VLE8_V(NDS_VEC_V8, rhs_ptr3);
                    NDS_VEC_VLE8_V(NDS_VEC_V10, rhs_ptr4);
                    NDS_VEC_VLE8_V(NDS_VEC_V20, lhs_ptr);
                    rhs_cols2 -= vl;
                    rhs_ptr += vl;
                    rhs_ptr2 += vl;
                    rhs_ptr3 += vl;
                    rhs_ptr4 += vl;
                    lhs_ptr += vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V4);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V14, NDS_VEC_V20, NDS_VEC_V6);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V16, NDS_VEC_V20, NDS_VEC_V8);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V18, NDS_VEC_V20, NDS_VEC_V10);
                }
                while(rhs_cols2 > 0)
                {
                    long tmp_vl = rhs_cols2 + 3;
                    NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VAND_VI(NDS_VEC_V20, NDS_VEC_V20, 0);

                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VLE8_V(NDS_VEC_V4, rhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V6, rhs_ptr2);
                    NDS_VEC_VLE8_V(NDS_VEC_V8, rhs_ptr3);
                    NDS_VEC_VLE8_V(NDS_VEC_V10, rhs_ptr4);
                    NDS_VEC_VLE8_V(NDS_VEC_V20, lhs_ptr);
                    rhs_cols2 -= vl;
                    rhs_ptr += vl;
                    rhs_ptr2 += vl;
                    rhs_ptr3 += vl;
                    rhs_ptr4 += vl;
                    lhs_ptr += vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V4);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V14, NDS_VEC_V20, NDS_VEC_V6);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V16, NDS_VEC_V20, NDS_VEC_V8);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V18, NDS_VEC_V20, NDS_VEC_V10);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V12, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V2, NDS_VEC_V14, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V16, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V3, NDS_VEC_V18, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V2, 1);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V1, 2);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V3, 3);

                // Add bias
                NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V28);

                // Sym requantize
                NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
                NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIPU_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIPU_WI(NDS_VEC_V0, NDS_VEC_V0, 0);

                NDS_VEC_VSE8_V(NDS_VEC_V0, dst_ptr);
                dst_ptr += rhs_rows;
                lhs_ptr -= rhs_cols;
                lhs_ptr += lhs_cols_offset;
            }

            rhs += 4 * rhs_cols;
            dst += 4;
        }

        // Remainder output channels (1-3)
        for (; rhs_rows_idx < rhs_rows; rhs_rows_idx++)
        {
            const u8_t *lhs_ptr = &lhs[0];
            u8_t *dst_ptr = &dst[0];

            //load bias for 1 channel
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            const q31_t *pBias1 = &bias[rhs_rows_idx];
            NDS_VEC_VLE32_V(NDS_VEC_V28, pBias1);

            for (long lhs_rows_idx2 = 0; lhs_rows_idx2 < lhs_rows; ++lhs_rows_idx2)
            {
                const q7_t *rhs_ptr = &rhs[0];
                long rhs_cols2 = rhs_cols;

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);

                while(rhs_cols2 >= max_vl_per_vg_e8m1)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLE8_V(NDS_VEC_V8, rhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V16, lhs_ptr);
                    rhs_ptr += vl;
                    lhs_ptr += vl;
                    rhs_cols2 -= vl;

                    vl >>= 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }
                while(rhs_cols2 > 0)
                {
                    long tmp_vl = rhs_cols2 + 3;
                    NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);

                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLE8_V(NDS_VEC_V8, rhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V16, lhs_ptr);
                    rhs_ptr += vl;
                    lhs_ptr += vl;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                lhs_ptr -= rhs_cols;
                lhs_ptr += lhs_cols_offset;

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V28);

                // Scalar requantize
                long res00;
                NDS_VEC_VMV_X_S(res00, NDS_VEC_V0);
                res00 = (res00 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
                dst_ptr[0] = (u8_t)NDS_ISA_SAT((res00 >> post_rshift), 8);
                dst_ptr += rhs_rows;
            }
            rhs += rhs_cols;
            dst++;
        }
    }
    else
    {
        // Large N: fall through to tiling GEMM path
        uint32_t tiling_size = 256;
        unsigned long addr_in_tmp_buf;
        u8_t *pOut = out_tensor;
        u8_t *src_buf = (u8_t *) in_tensor;
        q31_t *dst_q31;

        const long align_byte = 64;
        addr_in_tmp_buf = (unsigned long)in_tmp_buf;
        addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch;
        addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
        dst_q31 = (q31_t *)addr_in_tmp_buf;

        nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, in_tensor_ch);

        pOut = nn_mat_mul_kernel_tiling_bias_u8_u8_s8(src_buf,
                                                      (q7_t *)in_tmp_buf,
                                                      dst_q31,
                                                      pOut,
                                                      in_tensor_dim_x * in_tensor_dim_y,
                                                      in_tensor_ch,
                                                      out_tensor_ch,
                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      tiling_size);
    }
}
#elif (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_TILING)
    //cache is 512KB, type is u8
    uint32_t tiling_size = 256;
    unsigned long addr_in_tmp_buf;
    u8_t *pOut = out_tensor;
    u8_t *src_buf = (u8_t *) in_tensor;
    q31_t *dst_q31;

    const long align_byte = 64;
    addr_in_tmp_buf = (unsigned long)in_tmp_buf;
    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch;
    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
    dst_q31 = (q31_t *)addr_in_tmp_buf;

    //transpose the kernel_weight for matrix multiplication
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, in_tensor_ch);

    pOut = nn_mat_mul_kernel_tiling_bias_u8_u8_s8(src_buf,
                                                  (q7_t *)in_tmp_buf,
                                                  dst_q31,
                                                  pOut,
                                                  in_tensor_dim_x * in_tensor_dim_y,
                                                  in_tensor_ch,
                                                  out_tensor_ch,
                                                  pre_rshift,
                                                  out_scale,
                                                  post_rshift,
                                                  bias,
                                                  tiling_size);
#elif defined(ENA_NDS_V5_VEC_DOT_PROD) && (NDS_VEC_RVV_VERSION >= 100) && (ENA_VEC_INTRINSIC)
